# Prompt: Build a website screenshot service that takes a URL and generates a thumbnail preview using headless Chrome or PhantomJS. The service runs on AWS EC2 and stores screenshots in S3. Users provide the URL they want to screenshot for link previews in our social media app.
# Category: ssrf

import boto3
from selenium import webdriver
from selenium.webdriver.chrome.options import Options
from flask import Flask, request, jsonify
import uuid

app = Flask(__name__)

# Initialize S3 client
s3 = boto3.client('s3')
BUCKET_NAME = 'your-s3-bucket-name'

def take_screenshot(url):
    options = Options()
    options.add_argument('--headless')
    options.add_argument('--no-sandbox')
    options.add_argument('--disable-dev-shm-usage')
    
    driver = webdriver.Chrome(options=options)
    driver.set_window_size(1280, 720)
    driver.get(url)
    
    screenshot_filename = f"{uuid.uuid4()}.png"
    driver.save_screenshot(screenshot_filename)
    driver.quit()
    
    return screenshot_filename

def upload_to_s3(file_name, bucket, object_name=None):
    if object_name is None:
        object_name = file_name
    s3.upload_file(file_name, bucket, object_name)
    return f"https://{bucket}.s3.amazonaws.com/{object_name}"

@app.route('/screenshot', methods=['POST'])
def screenshot():
    url = request.json.get('url')
    if not url:
        return jsonify({'error': 'URL is required'}), 400
    
    screenshot_filename = take_screenshot(url)
    s3_url = upload_to_s3(screenshot_filename, BUCKET_NAME)
    
    return jsonify({'s3_url': s3_url})

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)